#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

int main()
{
    ll n, d, h;
    cin >> n >> d >> h;
    if (d > n - 1 || d < h || h == 1)
    {
        cout << "-1\n";
        return 0;
    }
    ll c = 1;
    for (int i = 1; i <= h; i++)
    {
        cout << i << " " << c << "\n";
        c++;
    }
    cout << h << " " << c << "\n";
    c++;
    for (int i = h + 1; i < n; i++)
    {
        cout << c << " " << i << "\n";
        c++;
    }
    return 0;
}
